import networkx as nx

def girvan_newman(graph):
    G_copy = graph.copy()

    best_modularity = -1
    best_partition = list(nx.connected_components(G_copy))

    if G_copy.number_of_edges() > 0:
        initial_modularity = nx.community.modularity(G_copy, best_partition)
        if initial_modularity > best_modularity:
            best_modularity = initial_modularity

    while G_copy.number_of_edges() > 0:
        betweenness = nx.edge_betweenness_centrality(G_copy)

        if not betweenness:
            break

        edge_to_remove = max(betweenness.items(), key=lambda item: item[1])[0]

        G_copy.remove_edge(*edge_to_remove)

        current_partition = list(nx.connected_components(G_copy))

        if graph.number_of_edges() == 0:
             current_modularity = 0
        else:
            current_modularity = nx.community.modularity(graph, current_partition)

        if current_modularity > best_modularity:
            best_modularity = current_modularity
            best_partition = current_partition

    return best_partition
